  'shaoxing/pen': ('Колыбель каллиграфии', 'Павильон Ланьтин, связанный с именем мастера Ван Сичжи, считается священным местом для всех любителей каллиграфии.'),
  'shaoxing/boat': ('Лодки «упэн»', 'Традиционные лодки с черным навесом, которыми управляют с помощью ног, являются классическим способом передвижения по каналам.'),
  'bengbu/shell': ('Жемчужная гавань', 'Название города переводится как «пристань устриц», так как раньше он славился добычей жемчуга в реке Хуайхэ.'),
  'bengbu/train': ('Железнодорожный узел Бэнбу', 'Город вырос вокруг станции, расположенной на пересечении важнейшей железнодорожной магистрали север-юг через реку Хуайхэ.'),
  'bengbu/river': ('Река Хуайхэ', 'Именно здесь протекает река, которая традиционно считается географической границей между севером и югом Китая.'),
  'bengbu/blossom': ('Весенние ярмарки', 'Каждую весну городские парки на берегах реки наполняются праздничными ярмарками в период цветения.'),
  'jiujiang/mountain': ('Гора Лушань', 'Туманные вершины горы Лушань, включенной в список объектов всемирного наследия ЮНЕСКО, веками вдохновляли китайских поэтов и художников.'),
  'jiujiang/tea': ('Чай Юньу', 'Выращенный на склонах горы Лушань чай «Облака и туманы» считается одним из самых изысканных сортов в Китае.'),
  'jiujiang/lake': ('Озеро Поянху', 'Крупнейшее пресноводное озеро Китая служит местом зимовки для тысяч журавлей.'),
  'jiujiang/scroll': ('Город поэтов', 'В этом городе у реки когда-то черпали вдохновение и создавали свои бессмертные строки великие поэты Бай Цзюйи и Су Ши.'),
  'quanzhou/ship': ('Морской Шелковый путь', 'Средневековый порт Цюаньчжоу, известный Марко Поло как «Зайтун», в свое время был крупнейшим торговым центром мира и сегодня находится под охраной ЮНЕСКО.'),
  'quanzhou/mosque': ('Мечеть Цинцзин', 'Построенная в 1009 году каменная мечеть является одной из старейших в Китае.'),
  'quanzhou/puppet': ('Театр марионеток', 'Искусство управления нитяными куклами в Цюаньчжоу — это древняя сценическая традиция с тысячелетней историей.'),
  'quanzhou/tea': ('Чай Тегуаньинь', 'Знаменитый во всем мире улун «Железная бодхисаттва» родом из соседнего уезда Аньси.'),
  'shanghai/pearl': ('Телебашня «Восточная жемчужина»', 'Возвышающаяся над рекой Хуанпу башня со своими розовыми сферами стала настоящим символом современного Шанхая.'),
  'shanghai/bund': ('Набережная Вайтань', 'Историческая набережная с фасадами старинных отелей отражает былое величие Шанхая.'),
  'shanghai/garden': ('Сад Юйюань', 'Классический сад эпохи Мин с его причудливыми скалами и прудами — это тихий оазис в самом сердце мегаполиса.'),
  'shanghai/xlb': ('Сяолунбао', 'Паровые пельмени с горячим бульоном внутри — главный шедевр шанхайского завтрака.'),
  'hangzhou/lake': ('Сиху', 'Это озеро с ивами, островками и арочными мостиками — самое воспеваемое в китайской поэзии место.'),
  'hangzhou/tea': ('Чай Лунцзин', 'Выращенный на склонах вокруг озера, зеленый чай «Колодец дракона» считается самым известным в Китае.'),
  'hangzhou/temple': ('Храм Линъинь', 'Этот 1700-летний «Храм прибежища души» славится своими наскальными рельефами и гигантской статуей Будды.'),
  'hangzhou/silk': ('Город шелка', 'Ханчжоуский шелк ткут уже тысячу лет — именно он составлял богатство восточного конца Великого шелкового пути.'),
  'chongqing/hongya': ('Хунъядун', 'Этот комплекс домов на сваях, цепляющийся за скалу, по ночам сияет над рекой, словно сказочный дворец.'),
  'chongqing/hotpot': ('Чунцинский хого', 'Блюдо, бурлящее в остром масле с пряным перцем, является огненной душой этого горного города.'),
  'chongqing/monorail': ('Чунцинский монорельс', 'Монорельсовая дорога, проходящая прямо сквозь жилой дом, — визитная карточка этого города, построенного на холмах.'),
  'chongqing/river': ('Ущелья Янцзы', 'Круизные лайнеры отправляются из этого порта, где город возвышается над местом слияния двух великих рек.'),
  'dalian/square': ('Площадь Синхай', 'Крупнейшая городская площадь в Азии, где на побережье постоянно проходят фестивали и шоу.'),
  'dalian/beach': ('Пляжи Даляня', 'Благодаря скалистым бухтам и прохладному лету Далянь считается любимым морским курортом севера страны.'),
  'dalian/football': ('Футбольный город', 'Далянь называют «колыбелью китайского футбола», ведь именно здесь зародились самые титулованные клубы страны.'),
  'dalian/seafood': ('Морепродукты', 'Гребешки, креветки и морские ежи из холодных вод Желтого моря — главное украшение столов в этом городе.'),
  'shenyang/palace': ('Мукденский дворец', 'Первая резиденция династии Цин, которую часто называют младшим братом пекинского Запретного города.'),
  'shenyang/tomb': ('Гробницы династии Цин', 'Восточная и Северная гробницы, окружающие город, являются монументальными мавзолеями основателей династии.'),
  'shenyang/factory': ('Колыбель промышленности', 'Здесь зародилась тяжелая промышленность Китая, а за обилие огромных заводов город прозвали «Восточным Руром».'),
  'shenyang/dumpling': ('Пельмени «Лаобянь»', 'Двухсотлетние паровые пельмени «Лаобянь» — это визитная карточка кухни северного Китая.'),
  'hefei/judge': ('Храм Бао-гуна', 'Уроженец этих мест, честный судья Бао Чжэн стал символом справедливости, а его храм — памятником неподкупности.'),
  'hefei/science': ('Научный центр', 'Технологический хаб, объединяющий ведущие университеты и научно-исследовательские лаборатории Китая.'),
  'hefei/lake': ('Озеро Чаоху', 'Одно из пяти крупнейших пресноводных озер Китая, знаменитое своими сигами и крабами.'),
  'hefei/cake': ('Кунжутный пирог Лу', 'Сладкий кунжутный пирог — это старинное лакомство, традиционное для древнего города Лучжоу.'),
  'foshan/wingchun': ('Вин-чунь', 'Родина боевого искусства вин-чунь, где зародились традиции Ип Мана и Брюса Ли.'),
  'foshan/lion': ('Танец льва', 'Столица южного танца льва, где во время праздников яркие фигуры львов грациозно прыгают по столбам.'),
  'foshan/ceramic': ('Керамика Шивань', 'В местных печах с тысячелетней историей до сих пор создают знаменитые живые фигурки из керамики Шивань.'),
  'foshan/opera': ('Кантонская опера', 'Любимое сценическое искусство Южного Китая, которое сформировалось и достигло расцвета именно на этих землях.'),
  'guiyang/pavilion': ('Павильон Цзясю', 'Трехъярусный павильон на реке Наньмин уже 400 лет является главным символом города.'),
  'guiyang/sourfish': ('Рыба в кислом супе', 'Рыба, томленая в остро-кислом бульоне из ферментированных томатов, — это фирменное блюдо провинции Гуйчжоу.'),
  'guiyang/waterfall': ('Водопад Хуангошу', 'Один из крупнейших водопадов Азии с грохотом низвергается вниз, создавая в брызгах радужные переливы.'),
  'guiyang/miao': ('Культура народа мяо', 'Праздники и вышивка народа мяо, украшенного серебряными головными уборами, оживляют горные деревни.'),
  'changchun/film': ('Киногород', 'Здесь расположены студии, где зародился китайский кинематограф, за что город называют «Восточным Голливудом».'),
  'changchun/car': ('Автомобильная столица', 'Именно на местных заводах был выпущен первый автомобиль китайского производства, что сделало город автомобильным центром страны.'),
  'changchun/palace': ('Дворец марионеточного императора', 'Дворец, в котором жил последний император Китая, стал безмолвным свидетелем бурных исторических событий.'),
  'changchun/snow': ('Зимние снега', 'Долгими белыми зимами город сверкает ледяными скульптурами и горнолыжными трассами.'),
  'xining/lake': ('Озеро Кукунор', 'Крупнейшее соленое озеро Китая славится желтыми полями рапса, которые окружают его летом.'),
  'xining/monastery': ('Монастырь Таэр', 'Один из шести великих монастырей тибетского буддизма, знаменитый своими скульптурами из масла яка.'),
  'xining/flower': ('Цветение рапса', 'В июле высокогорное плато до самого горизонта покрывается золотистым ковром цветущего рапса.'),
  'xining/lamb': ('Яки и баранина', 'Лапша ручной работы и шашлыки из баранины в традициях хуэйской и тибетской кухни — главные вкусы этого плато.'),
  'guilin/karst': ('Карстовые горы реки Ли', 'Известняковые пики, поднимающиеся из тумана, изображены на купюре в 20 юаней.'),
  'guilin/elephant': ('Гора Слоновий хобот', 'Скала в форме слона, опускающего хобот в реку, является любимым символом города.'),
  'guilin/terrace': ('Рисовые террасы Лунцзи', 'Террасы «Драконий хребет», опоясывающие склоны гор, представляют собой многовековую лестницу человеческого труда.'),
  'guilin/osmanthus': ('Цветение османтуса', 'Название города означает «лес османтуса», и осенью он утопает в сладком аромате этих цветов.'),
  'wenzhou/merchant': ('Дух предпринимательства', 'Вэньчжоуских бизнесменов часто называют «китайскими евреями» за их умение создавать торговые сети по всему миру.'),
  'wenzhou/shoe': ('Обувь и кожа', 'Огромная доля кожаной обуви в мире производится именно в этом промышленном городе.'),
  'wenzhou/mountain': ('Горы Яньданшань', 'Эти горы, знаменитые своими водопадами и острыми пиками, называют «первыми горами у моря».'),
  'wenzhou/seafood': ('Морепродукты', 'Кальмары, гребешки и рыба из Восточно-Китайского моря составляют основу местного рациона.'),
  'tangshan/memorial': ('Мемориал землетрясения', 'Мемориальный парк, посвященный разрушительному землетрясению 1976 года, стал символом возрожденного города.'),
  'tangshan/coal': ('Уголь и сталь', 'Здесь были открыты первая в Китае современная угольная шахта и железная дорога, ставшие колыбелью национальной промышленности.'),
  'tangshan/ceramic': ('Таншаньский фарфор', 'Этот «северный город фарфора» славится своим изысканным костяным фарфором, который украшает столы по всему миру.'),
  'tangshan/lake': ('Парк Наньху', 'Живописный парк с озером, разбитый на месте бывшего угольного карьера, стал «зелеными легкими» города.'),
  'anshan/steel': ('Стальной город', 'Здесь был основан крупнейший в Китае металлургический комбинат, закрепивший за Аньшанем статус «стальной столицы» страны.'),
  'anshan/jade': ('Сюяньский нефрит', 'В этом городе находится самая большая в мире нефритовая скульптура, а сам регион по праву считается нефритовой сокровищницей Китая.'),
  'anshan/mountain': ('Гора Цяньшань', 'Священная гора «Тысячи лотосов» с ее древними храмами и отвесными скалами считается главной вершиной северо-востока страны.'),
  'anshan/spring': ('Горячие источники Танганцзы', 'Целебные горячие источники, которые на протяжении тысячи лет посещали даже китайские императоры.'),
  'linyi/market': ('Оптовый рынок Линьи', 'Крупнейший в Северном Китае оптовый торговый центр, откуда товары отправляются во все уголки страны.'),
  'linyi/brush': ('Родина каллиграфии', 'Здесь родился «мудрец каллиграфии» Ван Сичжи, поэтому город по праву называют краем туши и кисти.'),
  'linyi/mountain': ('Гора Мэншань', 'Вторая по высоте гора провинции Шаньдун, известная своим чистейшим воздухом и живописными водопадами.'),
  'linyi/pancake': ('Блины Имын', 'Тонкие кукурузные блины «цзяньбин» являются традиционным и любимым блюдом жителей горных районов Имын.'),
  'cangzhou/lion': ('Железный лев', 'Огромная статуя железного льва, отлитая более тысячи лет назад, является главным символом и гордостью города.'),
  'cangzhou/martial': ('Боевые искусства', 'Цанчжоу называют «домом ушу» — именно отсюда вышли многие прославленные мастера и школы боевых искусств.'),
  'cangzhou/canal': ('Великий канал', 'Через город проходит Великий канал Пекин — Ханчжоу, на берегах которого до сих пор сохранились старинные пристани.'),
  'cangzhou/jujube': ('Золотой зизифус', 'Сладкий «золотой» зизифус с тонкой кожицей по праву считается королем сухофруктов.'),
  'nantong/textile': ('Город текстиля', 'Наньтун считается столицей домашнего текстиля, а местный хлопок поставляется на рынки по всему миру.'),
  'nantong/mountain': ('Гора Ланшань', 'Эта священная гора с пятью вершинами, возвышающаяся в устье Янцзы, является местом паломничества и славится своими живописными видами.'),
  'nantong/kite': ('Поющие воздушные змеи', 'Традиционные воздушные змеи «баньяо», оснащенные специальными свистками, — это древний народный промысел города.'),
  'nantong/school': ('Пионер образования', 'Именно здесь промышленник Чжан Цзянь основал первые в Китае современные школы и музей.'),
  'taizhou/opera': ('Мэй Ланьфан', 'Тайчжоу — родина легендарного мастера пекинской оперы Мэй Ланьфана.'),
  'taizhou/tea': ('Утренний чай', 'Завтрак, состоящий из паровых булочек и свежезаваренного чая, является важным городским ритуалом.'),
  'taizhou/boat': ('Фестиваль лодок в Циньтуне', 'Весной река оживает благодаря красочному фестивалю, во время которого сотни гребцов соревнуются в скорости.'),
  'taizhou/meatball': ('Фрикадельки «Голова льва»', 'Крупные и нежные свиные фрикадельки «голова льва» — классическое блюдо хуайянской кухни.'),
  'jinhua/ham': ('Ветчина Цзиньхуа', 'Эта ветчина, приготовленная по старинному рецепту многовековой давности, считается самой знаменитой в Китае.'),
  'jinhua/film': ('Киностудия Хэндянь', 'Это крупнейшая в мире открытая съемочная площадка, где снимается бесчисленное множество исторических драм.'),
  'jinhua/cave': ('Пещера Шуанлун', 'В эту подземную пещеру посетители попадают на лодке через низкий каменный проход, что захватывает дух.'),
  'jinhua/bridge': ('Древние мосты', 'Арочные каменные мосты и прибрежные городки воплощают в себе изящество региона Цзяннань.'),
  'wuhu/park': ('Парк развлечений «Фанте»', 'Один из крупнейших тематических парков Китая предлагает семьям незабываемый отдых, полный ярких впечатлений.'),
  'wuhu/ironart': ('Железная живопись', 'Изящные картины, выкованные из железа, представляют собой уникальное ремесло с трехсотлетней историей.'),
  'wuhu/rice': ('Рисовый порт', 'Этот город на берегу Янцзы исторически был крупнейшим центром торговли рисом в Китае.'),
  'wuhu/river': ('Порт Уху', 'Оживленный речной порт делает этот город главными морскими воротами провинции Аньхой.'),
  'huangshan/peak': ('Хуаншань', 'Гранитные пики, море облаков и причудливые сосны делают эту гору самой знаменитой в Китае.'),
  'huangshan/village': ('Деревня Хунцунь', 'Белостенные деревни в стиле Хуэй с каналами внесены в список всемирного наследия ЮНЕСКО и выглядят как ожившие картины.'),
  'huangshan/tea': ('Чай Маофэн', 'Этот зеленый чай с пушистыми почками, собранный на туманных склонах, входит в десятку самых знаменитых чаев Китая.'),
  'huangshan/ink': ('Хуэйская тушь и искусство', 'Хуэйская тушь, резные деревянные дома и каллиграфия являются культурным достоянием этого региона.'),
  'yichun/moon': ('Гора Минъюэ', 'Гора «Яркой луны» славится своими горячими источниками и живописными видами, открывающимися из кабинок канатной дороги.'),
  'yichun/spring': ('Горячие источники', 'Редкие термальные источники, богатые селеном, сделали этот город центром спа-курортов Китая.'),
  'yichun/zen': ('Чань-буддизм', 'Горные храмы, ставшие колыбелью китайских сект чань-буддизма, приглашают к обретению внутреннего покоя.'),
  'yichun/rice': ('Рисовая равнина', 'Плодородная равнина Юаньхэ издавна считается главной житницей провинции Цзянси.'),
  'zhangzhou/narcissus': ('Нарцисс', 'Здесь выращивают самые известные в Китае луковицы нарциссов, которые стали символом весенних праздников.'),
  'zhangzhou/tulou': ('Тулоу', 'Гигантские круглые крепости из утрамбованной земли внесены в список ЮНЕСКО и объединяют под одной крышей целую деревню.'),
  'zhangzhou/banana': ('Тропические фрукты', 'Рощи бананов, лонгана и мандаринов сохраняют тепло дельты зеленым круглый год.'),
  'zhangzhou/coast': ('Остров Дуншань', 'Золотистые пляжи и рыбацкие деревни делают этот остров жемчужиной южного побережья.'),
  'guangzhou/tower': ('Телебашня Гуанчжоу', 'Изящная «Тонкая талия», одна из самых высоких башен в мире, украшает город переливающимися ночными огнями.'),
  'guangzhou/dimsum': ('Утренний чай', '«Ям ча» — димсамы, приготовленные на пару в бамбуковых корзинках и поданные с чаем, являются душой кантонской кухни.'),
  'guangzhou/academy': ('Храм предков клана Чэнь', 'Этот родовой храм, знаменитый своей резьбой по дереву и керамическими фризами, считается шедевром кантонского зодчества.'),
  'guangzhou/flower': ('Город цветов', 'Благодаря цветущим круглый год растениям и масштабным новогодним цветочным ярмаркам Гуанчжоу называют «городом цветов».'),
  'wuhan/crane': ('Башня Желтого журавля', 'Эта тысячелетняя башня, возвышающаяся над Янцзы, вдохновила китайских поэтов на создание множества знаменитых произведений.'),
  'wuhan/noodle': ('Лапша «Ганьмянь»', 'Горячая сухая лапша с кунжутной пастой — это самый популярный и незаменимый завтрак в Ухане.'),
  'wuhan/duckneck': ('Острые утиные шеи', 'Тушеные в специях утиные шеи — любимая закуска горожан для вечерних посиделок.'),
  'wuhan/university': ('Сакура в Уханьском университете', 'Каждую весну полюбоваться цветением сакуры в кампусе Уханьского университета приезжают тысячи туристов.'),
  'tianjin/eye': ('Тяньцзиньское око', 'Это колесо обозрения, установленное прямо на мосту, открывает панорамный вид на оба берега реки.'),
  'tianjin/baozi': ('Баоцзы «Гоубули»', 'Паровые булочки с мясной начинкой и характерными защипами являются визитной карточкой города уже более 150 лет.'),
  'tianjin/crosstalk': ('Сяншэн', 'Традиционный жанр разговорной комедии «сяншэн» зародился в тяньцзиньских чайных домах.'),
  'tianjin/architecture': ('Европейский квартал', 'Благодаря виллам в европейском стиле в районе «Пяти великих проспектов» Тяньцзинь часто называют музеем архитектуры под открытым небом.'),
  'xiamen/island': ('Остров Гуланъюй', 'Этот остров, включенный в список всемирного наследия ЮНЕСКО, славится своими колониальными виллами и отсутствием автомобильного движения.'),
  'xiamen/piano': ('Остров пианино', 'Гуланъюй называют «островом пианино», так как здесь на душу населения приходится больше музыкальных инструментов, чем где-либо еще.'),
  'xiamen/egret': ('Белая цапля', 'Белая цапля является символом Сямыня и напоминает о старом названии города — «остров цапель».'),
  'xiamen/oyster': ('Омлет с устрицами', 'Хрустящий омлет со свежими устрицами — главное блюдо местной прибрежной кухни.'),
  'harbin/ice': ('Харбинский фестиваль льда и снега', 'Зимний фестиваль с гигантскими ледяными дворцами и яркой иллюминацией является крупнейшим событием такого рода в мире.'),
  'harbin/cathedral': ('Софийский собор', 'Этот православный собор с куполами-луковицами является символом европейского прошлого города.'),
  'harbin/sausage': ('Харбинская красная колбаса', 'Копченая колбаса в русском стиле — это местный деликатес с вековой историей.'),
  'harbin/accordion': ('Музыкальный город', 'Благодаря богатому русскому наследию именно в Харбине был основан первый в Китае симфонический оркестр.'),
  'fuzhou/alley': ('Три переулка и семь аллей', 'Этот старинный квартал с белыми стенами и черной черепицей представляет собой живой музей архитектуры эпох Мин и Цин.'),
  'fuzhou/banyan': ('Город баньянов', 'Фучжоу называют «городом баньянов» из-за древних гигантских деревьев, создающих густую тень на улицах.'),
  'fuzhou/hotspring': ('Горячие источники', 'Бьющие прямо в центре города горячие источники питают общественные купальни уже на протяжении тысячи лет.'),
  'fuzhou/soup': ('Будда прыгает через стену', 'Этот изысканный суп, приготовленный из десятков ингредиентов, считается главным шедевром фуцзяньской кухни.'),
  'dongguan/robot': ('Мировая фабрика', 'Благодаря автоматизированным производствам Дунгуань выпускает огромную долю всей мировой электроники.'),
  'dongguan/basketball': ('Баскетбольный город', 'В этом городе, который называют «баскетбольной столицей», базируется самый титулованный баскетбольный клуб Китая.'),
  'dongguan/keyuan': ('Сад Кэюань', 'Один из четырех знаменитых классических садов провинции Гуандун, известный своими прудами и изящными павильонами.'),
  'dongguan/cannon': ('Крепость Хумень', 'Форты Хумень, где началась Опиумная война, стоят на берегу, где когда-то уничтожали партии опиума.'),
  'lanzhou/beefnoodle': ('Ланьчжоуская лапша с говядиной', 'Ланьчжоу по праву считается столицей лапши благодаря своему прозрачному говяжьему бульону и мастерству ручной вытяжки теста.'),
  'lanzhou/waterwheel': ('Водяные колеса', 'Гигантские водяные колеса на реке Хуанхэ символизируют многовековую историю ирригационной инженерии.'),
  'lanzhou/statue': ('Скульптура «Мать — Желтая река»', 'Эта статуя матери с ребенком на берегу олицетворяет великую реку, ставшую колыбелью китайской цивилизации.'),
  'lanzhou/raft': ('Плот из овечьих шкур', 'Традиционные плоты, сделанные из надутых овечьих шкур, до сих пор можно встретить на реке Хуанхэ.'),
  'urumqi/bazaar': ('Международный большой базар', 'С его минаретами и прилавками с пряностями базар сохраняет колорит Великого шелкового пути.'),
  'urumqi/tianshan': ('Тяньчи', 'Озеро Тяньчи, расположенное у подножия заснеженных пиков Тянь-Шаня, окружено густыми еловыми лесами.'),
  'urumqi/kebab': ('Шашлык из баранины', 'Пряный шашлык из баранины, приготовленный на углях, является неотъемлемой частью уйгурского застолья.'),
  'urumqi/dance': ('Уйгурский танец', 'Зажигательные уйгурские танцы под аккомпанемент барабанов и равапа украшают любой праздник.'),
  'haikou/coconut': ('Город кокосов', 'Улицы, обсаженные кокосовыми пальмами, подарили Хайкоу прозвище «город кокосов».'),
  'haikou/arcade': ('Аркады Цилоу', 'Южные здания с колоннадами в стиле «цилоу» образуют тенистые торговые улицы.'),
  'haikou/crater': ('Вулканические кратеры', 'Потухшие вулканические кратеры образуют зеленый геопарк на окраине города.'),
  'haikou/turtle': ('Тропическое море', 'Теплые прозрачные воды и коралловые рифы делают побережье идеальным домом для морских черепах.'),
  'luoyang/grotto': ('Гроты Лунмэнь', 'Десятки тысяч статуй Будды, высеченных в скалах, представляют собой сокровищницу искусства, включенную в список ЮНЕСКО.'),
  'luoyang/peony': ('Столица пионов', 'Тысячи пионов, расцветающих каждый апрель, делают Лоян настоящей «столицей пионов».'),
  'luoyang/whitehorse': ('Храм Белой лошади', 'Основанный в 68 году нашей эры, этот храм считается первым буддийским монастырем в Китае.'),
  'luoyang/capital': ('Древняя столица', 'Будучи столицей тринадцати династий, Лоян считается колыбелью китайской цивилизации.'),
  'shantou/gongfutea': ('Чайная церемония гунфу', 'Чаошаньский чай гунфу, который торжественно заваривают в крошечных чашках, является настоящим искусством гостеприимства.'),
  'shantou/beefpot': ('Говяжий хого', 'Чаошаньский хого, где тонкие ломтики свежей говядины варятся за считанные секунды, пользуется огромной популярностью.'),
  'shantou/opera': ('Чаочжоуская опера', '600-летняя чаочжоуская опера славится своим изящным пением и роскошными вышитыми костюмами.'),
  'shantou/harbor': ('Порт Шаньтоу', 'Этот город, ставший родиной для многих китайских эмигрантов, на протяжении веков служил важными морскими воротами для международной торговли.'),
  'baoding/mansion': ('Резиденция губернатора', 'Это прекрасно сохранившееся здание эпохи династии Цин когда-то было главной административной резиденцией провинции.'),
  'baoding/donkeyburger': ('Бургер с ослиным мясом', 'Фирменный местный стрит-фуд представляет собой хрустящую лепешку, начиненную пряным мясом осла.'),
  'baoding/balls': ('Шары здоровья', 'Традиционные металлические шары для упражнений, которые вращают в ладони, используются для улучшения здоровья уже много столетий.'),
  'baoding/reeds': ('Болота Байяндянь', 'Крупнейшая водно-болотная зона на севере Китая, утопающая в тростниках и лотосах, является настоящим раем для птиц.'),
  'jilin/rime': ('Иней на деревьях', 'Белоснежный иней, покрывающий деревья вдоль реки Сунгари, считается одним из четырех главных природных чудес Китая.'),
  'jilin/snowboard': ('Горнолыжный курорт', 'Благодаря глубокому снегу и продолжительному сезону город стал одним из лучших мест для катания на лыжах в северном Китае.'),
  'jilin/meteorite': ('Музей метеоритов', 'Здесь выставлен крупнейший в мире каменный метеорит, упавший на Землю в 1976 году.'),
  'jilin/skate': ('Замерзшая река Сунгари', 'Зимой замерзшая река Сунгари превращается в огромный каток, заполненный конькобежцами и гуляющими горожанами.'),
  'ordos/khan': ('Мавзолей Чингисхана', 'Величественный мавзолей, посвященный герою степей Чингисхану, является духовным центром монгольской культуры.'),
  'ordos/cashmere': ('Кашемир', 'Кашемир, изготовленный из шерсти ордосских коз, прославил город на мировом рынке текстиля.'),
  'ordos/sanddune': ('Поющие пески', 'Гигантские дюны в пустыне Кубуци, издающие гул при спуске с них, являются излюбленным местом туристов.'),
  'ordos/yurt': ('Монгольская юрта', 'Белые войлочные юрты, установленные посреди бескрайних степей, являются символом кочевого образа жизни.'),
  'jining/confucius': ('Храм Конфуция', 'Расположенные в соседнем Цюйфу храм, усадьба и могила великого мудреца Конфуция включены в список объектов всемирного наследия ЮНЕСКО.'),
  'jining/barge': ('Великий канал', 'Будучи оживленным портом на Великом канале Пекин — Ханчжоу, Цзинин исторически был важным центром культуры судоходства.'),
  'jining/sword': ('Герои Ляншаня', 'Сто восемь легендарных разбойников из классического романа «Речные заводи» собирались в этих болотистых холмах.'),
  'jining/fishnet': ('Озеро Вэйшань', 'На самом большом лотосовом озере севера рыбаки до сих пор используют старинные методы ловли.'),
  'langfang/culture': ('Культурный центр Шелкового пути', 'В этом современном масштабном центре под одной крышей собраны произведения искусства стран Шелкового пути.'),
  'langfang/furniture': ('Мебельный город', 'Соседний уезд Сянхэ является одним из крупнейших в Китае центров по производству и продаже мебели.'),
  'langfang/tunnel': ('Древние военные туннели', 'Тысячелетние подземные военные ходы когда-то служили важной линией обороны границы.'),
  'langfang/themepark': ('Парк «Город №1»', 'Огромный тематический парк, воссоздающий облик древнего города-крепости, открыт для семейного отдыха.'),
  'yancheng/salt': ('Город соли', 'Название города переводится как «соляная крепость», ведь на протяжении веков Яньчэн был центром соледобычи в Китае.'),
  'yancheng/crane': ('Японский журавль', 'Прибрежные водно-болотные угодья являются крупнейшим в мире местом зимовки диких японских журавлей.'),
  'yancheng/elk': ('Олень Давида', 'Когда-то исчезнувший в дикой природе вид оленя милу был успешно возрожден в этих заповедных местах.'),
  'yancheng/wetland': ('Прибрежные водно-болотные угодья', 'Включенные в список ЮНЕСКО приливные отмели служат важной остановкой для перелетных птиц со всего мира.'),
  'huzhou/brush': ('Кисть Ху', 'Знаменитая кисть Ху, одна из «четырех драгоценностей» китайской каллиграфии, производится именно здесь.'),
  'huzhou/bamboo': ('Бамбуковое море Аньцзи', 'Бескрайние зеленые бамбуковые леса, ставшие источником вдохновения для многих фильмов, дарят прохладу в жаркие дни.'),
  'huzhou/silkworm': ('Шелкопряд', 'Южный берег озера Тайху на протяжении тысячи лет остается центром производства шелка из тутового шелкопряда.'),
  'huzhou/whitetea': ('Белый чай из Аньцзи', 'Белый чай из Аньцзи с его нежными светлыми листьями и сладковатым вкусом считается одним из самых редких сортов в Китае.'),
  'quzhou/go': ('Вэйци', 'Благодаря легенде о горе Ланькэ город почитается как священная земля для любителей игры в го.'),
  'quzhou/peaks': ('Гора Цзянлан', 'Три гигантских каменных столба, устремленных в небо, образуют уникальный ландшафт, включенный в список объектов всемирного наследия ЮНЕСКО.'),
  'quzhou/ponkan': ('Мандарины понкань из Цюйчжоу', 'Сладкие мандарины понкань с тонкой кожицей — это зимний дар мягкого климата местных холмов.'),
  'quzhou/cake': ('Лепешки с кунжутом', 'Хрустящие кунжутные лепешки, выпеченные на стенках печи, являются классическим местным завтраком.'),
  'huainan/tofu': ('Родина тофу', 'Изобретенный на горе Багун две тысячи лет назад, тофу именно отсюда начал свое распространение по всему миру.'),
  'huainan/coalmine': ('Угольная столица', 'Богатый залежами угля, Хуайнань является важнейшей энергетической базой восточного Китая.'),
  'huainan/oldtown': ('Старый город Шоусянь', 'Полностью сохранившаяся городская стена эпохи Сун представляет собой редкий образец древнего оборонительного зодчества.'),
  'huainan/classic': ('Хуайнань-цзы', 'Классический философский трактат, составленный принцем Лю Анем, был написан именно на этих землях.'),
  'jingdezhen/porcelain': ('Фарфоровая столица', 'Производя императорский фарфор на протяжении тысячи лет, город по праву считается мировой столицей этого ремесла.'),
  'jingdezhen/kiln': ('Древние печи', 'Дровяные печи в форме дракона до сих пор поддерживают жизнь традиционного искусства обжига фарфора.'),
  'jingdezhen/bluewhite': ('Сине-белый фарфор', 'Белый фарфор с кобальтовой росписью является всемирно известной визитной карточкой города.'),
  'jingdezhen/painting': ('Фарфоровая живопись', 'Фарфор, расписанный мастерами с помощью тончайших кистей, ценится наравне с произведениями классической живописи.'),
  'jian/jinggang': ('Цзинганшань', 'Туманные горы, ставшие первой базой революции, являются сердцем «красного туризма».'),
  'jian/torch': ('Революционная искра', 'Земля, где зародилась идея о том, что «одна искра может разжечь пламя», стала важным историческим мемориалом.'),
  'jian/academy': ('Академия Байлучжоу', 'Тысячелетняя академия, расположенная на острове посреди реки Гань, воспитала бесчисленное множество имперских ученых.'),
  'jian/pine': ('Сосны Цзинганшаня', 'Красные сосны, пробивающиеся сквозь туман, символизируют горный дух и стойкость.'),
  'nanping/wuyi': ('Горы Уишань', 'Эти горы, включенные в список всемирного наследия ЮНЕСКО, славятся своими красными скалами и живописными зелеными ущельями.'),
  'nanping/rocktea': ('Утесный чай', 'Выращенный на скалах улун «Да Хун Пао» считается одним из самых дорогих сортов чая в мире.'),
  'nanping/bambooraft': ('Сплав по реке Цзюцюй', 'Бамбуковые плоты плавно скользят по извилистой реке Девяти излучин среди отвесных красных скал.'),
  'nanping/scholar': ('Чжу Си', 'Основоположник неоконфуцианства Чжу Си преподавал у подножия этих гор.'),
  'shenzhen/skyscraper': ('Небоскребы Шэньчжэня', 'Лес небоскребов, выросший на месте рыбацкой деревни всего за 40 лет, стал настоящим чудом китайских реформ.'),
  'shenzhen/chip': ('Технологический центр', 'Благодаря рынку электроники Хуацянбэй и штаб-квартирам гигантов индустрии Шэньчжэнь называют «китайской Кремниевой долиной».'),
  'shenzhen/miniature': ('Окно в мир', 'Этот тематический парк, где собраны миниатюрные копии знаменитых мировых достопримечательностей, является визитной карточкой города.'),
  'shenzhen/mangrove': ('Залив Шэньчжэнь', 'Поросший мангровыми лесами залив стал излюбленным местом обитания перелетных птиц и белых цапель.'),
  'xian/terracotta': ('Терракотовая армия', 'Тысячи глиняных воинов, охраняющих гробницу императора Цинь Шихуанди, называют восьмым чудом света.'),
  'xian/citywall': ('Городская стена Сианя', 'По лучшей в Китае сохранившейся крепостной стене эпохи Мин можно совершить велосипедную прогулку.'),
  'xian/drumtower': ('Колокольная башня', 'Расположенная в самом центре города Колокольная башня эпохи Мин считается сердцем древней столицы.'),
  'xian/roujiamo': ('Жоуцзямо', 'Это традиционное блюдо из рубленого мяса в хрустящей лепешке часто называют «китайским бургером» Великого шелкового пути.'),
  'suzhou/garden': ('Классические сады Сучжоу', 'Изящно спроектированные сады с искусственными скалами, прудами и павильонами включены в список всемирного наследия ЮНЕСКО.'),
  'suzhou/watertown': ('Водный город', 'Благодаря своим каналам, каменным мостам и белым домам Сучжоу часто называют «Восточной Венецией».'),
  'suzhou/embroidery': ('Сучжоуская вышивка', 'Двусторонняя вышивка шелком — это древнее ремесло Сучжоу с тысячелетней историей.'),
  'suzhou/kunqu': ('Опера Куньцюй', 'Изящная опера Куньцюй, которую считают прародительницей всех китайских оперных жанров, зародилась именно здесь.'),
  'kunming/stoneforest': ('Каменный лес', 'Гигантские известняковые столбы, формировавшиеся миллионы лет, образуют причудливый каменный лабиринт.'),
  'kunming/springcity': ('Город вечной весны', 'Благодаря мягкому климату Куньмин называют «городом вечной весны», где цветы не увядают круглый год.'),
  'kunming/seagull': ('Озерные чайки', 'Каждую зиму тысячи чаек, прилетающих из Сибири, превращают берега местных озер в сплошное белое полотно.'),
  'kunming/ricenoodle': ('Рисовая лапша «Гоцяо»', 'Тонкая рисовая лапша, которую добавляют в горячий бульон прямо за столом, является визитной карточкой кухни Юньнани.'),
  'jinan/spring': ('Город источников', 'Семьдесят два знаменитых родника, бьющих из-под земли, дали Цзинаню его второе имя — «город источников».'),
  'jinan/daminglake': ('Озеро Даминху', 'Это городское озеро, окруженное ивами и лотосами, питается водами местных родников.'),
  'jinan/buddhamountain': ('Гора Тысячи Будд', 'Эта гора является местом паломничества благодаря сотням статуй Будды, высеченным прямо в ее склонах.'),
  'jinan/poet': ('Поэтесса Ли Цинчжао', 'Величайшая китайская поэтесса Ли Цинчжао родилась в этом городе источников.'),
  'ningbo/library': ('Библиотека Тяньигэ', 'Библиотека Тяньигэ, основанная 450 лет назад, является старейшей сохранившейся частной библиотекой в Азии.'),
  'ningbo/port': ('Морской порт Нинбо-Чжоушань', 'Порт Нинбо-Чжоушань занимает первое место в мире по грузообороту.'),
  'ningbo/tangyuan': ('Танъюань', 'Сладкие шарики из клейкого риса с кунжутной начинкой — главный гастрономический символ города.'),
  'ningbo/seafood': ('Морепродукты', 'Желтый горбыль и крабы из Восточно-Китайского моря составляют основу местного рациона.'),
  'shijiazhuang/bridge': ('Мост Чжаочжоу', 'Этот каменный арочный мост, построенный 1400 лет назад, считается старейшим в мире мостом подобной конструкции.'),
  'shijiazhuang/clifftemple': ('Гора Цанъянь', 'Храм, расположенный на мосту между отвесными скалами, стал декорацией для множества кинофильмов.'),
  'shijiazhuang/redbase': ('Сибайпо', 'Деревня, где планировалось создание Нового Китая, является священным местом «красного туризма».'),
  'shijiazhuang/pharma': ('Фармацевтическая столица', 'Город является одним из крупнейших центров производства антибиотиков в Китае.'),
  'taiyuan/jincitemple': ('Храм Цзиньцы', 'Благодаря трехтысячелетним статуям и источникам, Цзиньцы считается самым изящным храмовым садом Северного Китая.'),
  'taiyuan/coalcart': ('Угольный край', 'Угольные пласты провинции Шаньси обеспечивают энергией весь Китай, а Тайюань является столицей этого богатства.'),
  'taiyuan/vinegar': ('Выдержанный уксус', 'Зрелый выдержанный уксус — это главный кислый ингредиент кухни провинции Шаньси.'),
  'taiyuan/twinpagoda': ('Двойные пагоды', 'Две восьмиугольные пагоды эпохи Мин, ставшие символом города, возвышаются бок о бок.'),
  'hohhot/lamatemple': ('Храм Дачжао', 'Этот тибетский буддийский монастырь, известный своей статуей Серебряного Будды, является духовным сердцем города.'),
  'hohhot/dairy': ('Молочная столица', 'Здесь зародились крупнейшие молочные бренды Китая, поэтому город называют «молочной столицей» страны.'),
  'hohhot/wrestling': ('Монгольская борьба', 'Борьба бёх, ставшая главным событием фестиваля Наадам, является демонстрацией силы степных воинов.'),
  'hohhot/prairie': ('Степь', 'За пределами города простираются зеленые монгольские степи, полные лошадей и стад.'),
  'sanya/resortbeach': ('Тропический пляж', 'Мелкозернистый песок и бирюзовая вода залива Ялунвань делают это место «китайскими Гавайями».'),
  'sanya/guanyin': ('Статуя Гуаньинь', 'Возвышающаяся на 108 метров над морем статуя богини Гуаньинь является одной из самых высоких в мире.'),
  'sanya/diving': ('Дайвинг', 'Благодаря теплым прозрачным водам и коралловым рифам Санья считается дайвинг-раем Китая.'),
  'sanya/coconutdrink': ('Кокос', 'Свежая кокосовая вода из тропических рощ — это лучшее освежающее лакомство на острове.'),
  'yangzhou/slenderlake': ('Тонкое Западное озеро', 'Благодаря ивам и белому мосту это изящное озеро выглядит словно ожившая картина.'),
  'yangzhou/friedrice': ('Янчжоуский жареный рис', 'Этот всемирно известный классический рис с креветками и яйцом обжаривается до золотистого цвета.'),
  'yangzhou/morningtea': ('Утреннее чаепитие', 'Изысканный завтрак с паровыми булочками и чаем — это настоящий ритуал жителей Янчжоу.'),
  'yangzhou/gegarden': ('Сад Гэюань', 'Этот шедевр классического садово-паркового искусства с бамбуковыми рощами и камнями воплощает в себе все четыре времени года.'),
  'weihai/navalisland': ('Остров Люгун', 'Будучи базой Бэйянского флота, этот остров является свидетелем истории военно-морского дела современного Китая.'),
  'weihai/swan': ('Лебединое озеро', 'Каждую зиму сотни лебедей-кликунов прилетают из Сибири, чтобы перезимовать в этой прибрежной лагуне.'),
  'weihai/seacucumber': ('Морской огурец', 'Выращенный в холодных и чистых водах, морской огурец считается самым ценным местным морепродуктом.'),
  'weihai/cape': ('Мыс Китая', 'На этом самом восточном мысе страны солнце встречает новый день раньше, чем где-либо еще в Китае.'),
  'handan/taichi': ('Тайцзицюань', 'Город Гуанфу, родина стилей Ян и У, по праву считается колыбелью боевого искусства тайцзицюань.'),
  'handan/congtai': ('Терраса Цунтан', 'Древняя земляная терраса времен царства Чжао хранит память о более чем двух тысячелетиях истории.'),
  'handan/idiom': ('Город идиом', 'Ханьдань называют «городом идиом», ведь именно здесь зародилось более полутора тысяч китайских фразеологизмов.'),
  'handan/ciporcelain': ('Керамика Цычжоу', 'Черно-белая керамика Цычжоу считается классическим образцом народного гончарного искусства.'),
  'daqing/oilpump': ('Нефтяное месторождение', 'Крупнейшее нефтяное месторождение Китая усеяно работающими станками-качалками.'),
  'daqing/oilworker': ('«Железный человек»', 'Мужество героя-нефтяника Ван Цзиньси стало основополагающим духом этого города.'),
  'daqing/reedlake': ('Водно-болотные угодья', 'Обширные тростниковые озера среди нефтяных вышек стали домом для журавлей и лебедей.'),
  'daqing/hotspring': ('Горячие источники', 'Подземные минеральные воды предлагают целетворный отдых посреди холодов северного края.'),
  'zibo/bbq': ('Цзыбоский шашлык', 'Шашлычки, приготовленные на маленьких жаровнях и завернутые в тонкие лепешки, стали настоящим гастрономическим хитом по всему Китаю.'),
  'zibo/cuju': ('Цзюйцзюй', 'Древнейшая в мире игра с мячом, напоминающая футбол, зародилась в Линьцзы, столице древнего царства Ци.'),
  'zibo/ceramic': ('Цзыбоская керамика', 'Благодаря своим печам с тысячелетней историей город по праву считается центром керамического производства Северного Китая.'),
  'zibo/glass': ('Люли', 'Люли — это традиционное ремесло изготовления изделий из цветного стекла, которые завораживают своей игрой света.'),
  'taian/mounttai': ('Тайшань', 'Главная из пяти священных гор даосизма, на вершине которой императоры совершали жертвоприношения небу.'),
  'taian/sunrise': ('Рассвет на вершине', 'Встреча солнца над морем облаков — главная награда для каждого, кто покорил вершину горы Тайшань.'),
  'taian/stonesteps': ('Каменная лестница', 'Путь к вершине, состоящий из семи тысяч каменных ступеней, является настоящим испытанием для паломников.'),
  'taian/daitemple': ('Храм Даймяо', 'Величественный храмовый комплекс у подножия горы, где императоры готовились к проведению священных ритуалов.'),
  'lianyungang/monkey': ('Гора Хуагошань', 'Здесь возвышается гора Хуагошань, известная как родина Царя обезьян из классического романа «Путешествие на Запад».'),
  'lianyungang/seaport': ('Морской порт', 'Восточные морские ворота Шелкового пути служат конечной точкой Евразийского сухопутного моста на побережье Тихого океана.'),
  'lianyungang/mountain': ('Гора Юньтайшань', 'Юньтайшань с ее крутыми пиками и густыми лесами является самой высокой горой в провинции Цзянсу.'),
  'lianyungang/crystal': ('Кристальный край', 'В соседнем уезде Дунхай находится один из крупнейших в мире рынков кварцевых кристаллов.'),
  'maanshan/libai': ('Поэт Ли Бо', 'В этом прибрежном городе находится последнее пристанище и могила величайшего китайского поэта Ли Бо.'),
  'maanshan/steel': ('Стальной город', 'Благодаря металлургическому комбинату «Маган» город стал одной из важнейших баз черной металлургии Китая.'),
  'maanshan/rivercliff': ('Утес Цайшицзи', 'Этот утес, обрывающийся прямо в воды Янцзы, стал местом действия легенд, связанных с именем поэта Ли Бо.'),
  'maanshan/moonwine': ('Луна и вино', 'Поэтические образы луны и вина, воспевавшиеся Ли Бо, до сих пор остаются центральными темами местных фестивалей на берегу реки.'),
  'longyan/tulou': ('Тулоу Юндина', 'Огромные круглые дома-крепости народа хакка, разбросанные по холмам, включены в список Всемирного наследия ЮНЕСКО.'),
  'longyan/redmeeting': ('Гутяньское совещание', 'В этой деревне состоялось историческое совещание, определившее дальнейший путь развития Красной армии.'),
  'longyan/hakka': ('Культура хакка', 'Народ хакка, переселившийся сюда с севера, бережно хранит свой уникальный язык и кулинарные традиции в этих горных районах.'),
  'longyan/mountain': ('Гора Гуаньчжи', 'Благодаря своим красным скалам и прозрачным водоемам эта гора считается природной жемчужиной южной части провинции Фуцзянь.'),
  'beijing/great-wall': ('Великая Китайская стена', 'Это самое длинное оборонительное сооружение в мире протяженностью более 20 000 км, а участок Бадалин рядом с Пекином является самым посещаемым благодаря своим каменным ступеням и сторожевым башням на гребнях гор.'),
  'beijing/temple': ('Храм Неба', 'Священный комплекс, где императоры династий Мин и Цин ежегодно молились о хорошем урожае, а его трехъярусная синяя крыша, построенная без единого гвоздя, стала одним из главных символов китайской архитектуры.'),
  'beijing/pagoda': ('Пагода Тяньнин', 'Эта 57-метровая 13-ярусная кирпичная пагода эпохи Ляо с резными рельефами и восьмиугольным основанием является одним из старейших сооружений Пекина, свидетельствующим о тысячелетней истории города.'),
  'beijing/opera': ('Пекинская опера', 'Традиционный китайский театр с двухсотлетней историей, сочетающий пение, диалоги, боевые искусства и акробатику, где грим актеров раскрывает характер персонажа: красный цвет символизирует верность, а белый — хитрость.'),
};
